function SearchToolbar({ filters, setFilters, resultCount }) {
  const activeFilterCount = [
    filters.query.trim() !== "",
    filters.stack !== "All",
    filters.availability !== "Any",
    filters.maxRate < 900,
  ].filter(Boolean).length;

  return (
    <div className="rounded-[32px] border border-slate-200 bg-white p-4 shadow-[0_1px_2px_rgba(15,23,42,0.04)] md:p-5">
      <div className="grid gap-4 xl:grid-cols-[1.8fr_0.9fr_0.9fr_1.1fr_auto] xl:items-end">
        <label className="block">
          <span className="mb-2 block text-xs font-medium uppercase tracking-[0.18em] text-slate-500">Search developers</span>
          <div className="relative">
            <Search className="pointer-events-none absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
            <input
              value={filters.query}
              onChange={(e) => setFilters((s) => ({ ...s, query: e.target.value }))}
              placeholder="React, Python, product engineer, London..."
              className="h-12 w-full rounded-2xl border border-slate-200 bg-white py-3 pl-11 pr-4 text-sm text-slate-950 outline-none transition placeholder:text-slate-400 focus:border-slate-400"
            />
          </div>
        </label>

        <FilterSelect value={filters.stack} onChange={(e) => setFilters((s) => ({ ...s, stack: e.target.value }))} options={stacks} label="Stack" />
        <FilterSelect value={filters.availability} onChange={(e) => setFilters((s) => ({ ...s, availability: e.target.value }))} options={availabilityOptions} label="Availability" />

        <label className="block">
          <span className="mb-2 block text-xs font-medium uppercase tracking-[0.18em] text-slate-500">Max day rate</span>
          <div className="rounded-2xl border border-slate-200 bg-white px-4 py-3">
            <div className="flex items-center justify-between gap-4 text-sm font-medium text-slate-700">
              <span>Budget cap</span>
              <span className="text-slate-950">£{filters.maxRate}</span>
            </div>
            <input
              type="range"
              min="300"
              max="900"
              step="10"
              value={filters.maxRate}
              onChange={(e) => setFilters((s) => ({ ...s, maxRate: Number(e.target.value) }))}
              className="mt-3 w-full accent-slate-900"
            />
          </div>
        </label>

        <button className="inline-flex h-12 items-center justify-center gap-2 rounded-2xl border border-slate-300 bg-slate-900 px-5 text-sm font-semibold text-white transition hover:bg-slate-800">
          <Filter className="h-4 w-4" />
          Apply
        </button>
      </div>

      <div className="mt-4 flex flex-col gap-3 border-t border-slate-100 pt-4 md:flex-row md:items-center md:justify-between">
        <div className="flex flex-wrap items-center gap-2 text-sm text-slate-600">
          <Pill tone="neutral">{resultCount} matches</Pill>
          {activeFilterCount > 0 ? <Pill tone="neutral">{activeFilterCount} active filters</Pill> : null}
        </div>
        <button
          onClick={() => setFilters({ query: "", stack: "All", availability: "Any", maxRate: 900 })}
          className="text-sm font-medium text-slate-500 transition hover:text-slate-900"
        >
          Reset filters
        </button>
      </div>
    </div>
  );
}

