function MarketplacePage({ filters, setFilters, onOpenProfile }) {
  const filtered = useMemo(() => {
    return developers.filter((dev) => {
      const q = filters.query.toLowerCase();
      const text = `${dev.name} ${dev.role} ${dev.skills.join(" ")} ${dev.summary} ${dev.location}`.toLowerCase();
      const matchesQuery = text.includes(q);
      const matchesStack = filters.stack === "All" || dev.skills.includes(filters.stack);
      const matchesAvailability = filters.availability === "Any" || dev.availability === filters.availability;
      const matchesBudget = dev.rate <= filters.maxRate;
      return matchesQuery && matchesStack && matchesAvailability && matchesBudget;
    });
  }, [filters]);

  return (
    <div className="space-y-10">
      <section className="rounded-[36px] border border-slate-200 bg-[linear-gradient(180deg,#ffffff_0%,#f8f8f7_100%)] p-8 md:p-10">
        <Pill tone="dark">Marketplace rebuilt for client hiring</Pill>
        <h2 className="mt-5 max-w-4xl text-4xl font-semibold tracking-tight text-slate-950 md:text-6xl">
          Book the right developer by stack, time, and cost.
        </h2>
        <p className="mt-5 max-w-2xl text-lg leading-8 text-slate-600">
          Clients search your talent pool, compare rates, check availability, and request developers without fighting the interface.
        </p>
        <div className="mt-10 grid gap-4 sm:grid-cols-2 xl:grid-cols-4">
          <StatCard label="Developer pool" value={stats.developerPool} hint="Across frontend, backend, AI, mobile, and DevOps" icon={Users} />
          <StatCard label="Average fill time" value={stats.averageFillTime} hint="For common stacks and shortlist requests" icon={Clock3} />
          <StatCard label="Bookings managed" value={stats.bookingsManaged} hint="Across trial, project, and retained engagements" icon={CalendarDays} />
          <StatCard label="Platform margin" value={stats.platformMargin} hint="Placeholder admin margin control" icon={Wallet} />
        </div>
      </section>

      <section>
        <SectionHeading
          eyebrow="Search and filter"
          title="Find developers fast"
          body="The darker version felt heavy. This version leans on white space, muted neutrals, and clearer hierarchy, which is closer to the current minimalist direction in web UI. citeturn374867search4turn374867search0"
        />
        <div className="mt-8">
          <SearchToolbar filters={filters} setFilters={setFilters} resultCount={filtered.length} />
        </div>

        <div className="mt-8 grid gap-5 xl:grid-cols-2">
          {filtered.length === 0 ? <EmptyState /> : filtered.map((dev) => <DeveloperCard key={dev.id} developer={dev} onOpenProfile={onOpenProfile} />)}
        </div>
      </section>
    </div>
  );
}

